const data = $input.first().json ?? {};

const workflowName = data.workflow?.name ?? data.execution?.workflowData?.name ?? 'Unknown workflow';
const workflowId = String(data.workflow?.id ?? data.execution?.workflowData?.id ?? data.execution?.workflowId ?? 'unknown-workflow');
const executionId = String(data.execution?.id ?? data.executionId ?? 'N/A');
const errorMessage = (data.error?.message ?? data.execution?.error?.message ?? data.message ?? 'Unknown error').toString();
const rawStack = (data.error?.stack ?? data.execution?.error?.stack ?? '').toString();
const firstStackLine = rawStack.split('\n').map((line) => line.trim()).filter(Boolean)[0] ?? '';
const timestamp = new Date().toISOString();

const devChatId = ($env.TELEGRAM_DEV_CHAT_ID ?? '').toString().trim();
const telegramConfigured = devChatId !== '' && devChatId !== 'CHANGE_ME';

function hashString(input) {
  let hash = 0;
  for (let i = 0; i < input.length; i++) {
    hash = ((hash << 5) - hash) + input.charCodeAt(i);
    hash |= 0;
  }
  return Math.abs(hash).toString(16);
}

const cooldownMs = 2 * 60 * 1000;
const now = Date.now();
const throttleStore = $getWorkflowStaticData('global');
if (!throttleStore.errorThrottle || typeof throttleStore.errorThrottle !== 'object') {
  throttleStore.errorThrottle = {};
}

const dedupeKey = `${workflowId}:${hashString(errorMessage)}`;
const lastSentAt = Number(throttleStore.errorThrottle[dedupeKey] ?? 0);
const throttled = lastSentAt > 0 && (now - lastSentAt) < cooldownMs;

if (!throttled) {
  throttleStore.errorThrottle[dedupeKey] = now;
}

const cutoff = now - (24 * 60 * 60 * 1000);
for (const [key, value] of Object.entries(throttleStore.errorThrottle)) {
  if (Number(value) < cutoff) {
    delete throttleStore.errorThrottle[key];
  }
}

const messageLines = [
  '⚠️ Aura n8n Error',
  `workflow: ${workflowName}`,
  `executionId: ${executionId}`,
  `error: ${errorMessage}`
];

if (firstStackLine) {
  messageLines.push(`stack: ${firstStackLine}`);
}

messageLines.push(`time: ${timestamp}`);

const shouldSend = telegramConfigured && !throttled;

return [{
  json: {
    message: messageLines.join('\n'),
    shouldSend,
    telegramConfigured,
    throttled,
    workflowId,
    executionId,
    errorMessage,
    firstStackLine,
    timestamp
  }
}];
